import scala.xml._

case class ConfigSetting(key: String, value: String)

object ConfigParserService {
  
  def parseConfig(xmlData: String): Seq[ConfigSetting] = {
    val xml = XML.loadString(xmlData)
    (xml \\ "setting").map { node =>
      val key = (node \ "key").text.trim
      val value = (node \ "value").text.trim
      ConfigSetting(key, value)
    }
  }
}

import akka.http.scaladsl.server.HttpApp
import akka.http.scaladsl.server.Route
import akka.http.scaladsl.server.Directives._

object ConfigServiceApp extends HttpApp {

  override protected def routes: Route =
    path("parseConfig") {
      post {
        entity(as[String]) { xmlData =>
          val settings = ConfigParserService.parseConfig(xmlData)
          complete(settings.map(s => s"${s.key}: ${s.value}").mkString("\n"))
        }
      }
    }
}

object WebServer extends App {
  ConfigServiceApp.startServer("localhost", 8080)
}